1	export type Scenario = {
2	  customer: { yearsWithMHPCO: number };
3	  steps: Array<unknown>;
4	};
5	
6	export type ScenarioResult = {
7	  results: Array<unknown>;
8	};
9	
10	export const runScenario = (_scenario: Scenario): ScenarioResult => {
11	  return { results: [{ premium: 5 }] };
12	};
13

1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Edge case: empty quote ---
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Single-item base premiums + processing fee ---
15	  it.todo("quote with a single plain sword → premium 105 G (100 base + 5 fee)");
16	  it.todo("quote with a single plain amulet → premium 65 G (60 base + 5 fee)");
17	  it.todo("quote with a single plain staff → premium 85 G (80 base + 5 fee)");
18	  it.todo("quote with a single plain potion → premium 45 G (40 base + 5 fee)");
19	
20	  // --- Components ---
21	  it.todo("quote with a single rune → premium 30 G (25 base + 5 fee)");
22	  it.todo("quote with 2 runes → 50 G base + 5 fee = 55 G");
23	  it.todo("quote with 3 runes (block) → 60 G base + 5 fee = 65 G");
24	  it.todo("quote with 4 runes → 100 G base + 5 fee = 105 G (no block — block requires exactly 3)");
25	  it.todo("quote with 7 runes → 175 G base + 5 fee = 180 G");
26	
27	  // --- 'Alike' clarification ---
28	  it.todo("quote with 2 runes + 1 moonstone → 75 G base + 5 fee = 80 G (no block — different types)");
29	  it.todo("quote with 3 runes + 3 moonstones → 120 G base + 5 fee = 125 G (two separate blocks)");
30	
31	  // --- Item-specific modifiers in isolation ---
32	  it.todo("cursed sword (no other modifiers) → 100 base + 50 curse + 5 fee = 155 G");
33	  it.todo("sword with enchantment 5 → 100 base + 30 high-enchantment + 5 fee = 135 G");
34	  it.todo("sword with enchantment 4 → no high-enchantment surcharge → 105 G");
35	  it.todo("cursed sword with enchantment 5 → both surcharges → 100 + 50 + 30 + 5 = 185 G");
36	
37	  // --- Policy-wide modifiers in isolation ---
38	  it.todo("loyalty discount: 2-year customer, plain sword → 100 − 20 + 5 = 85 G");
39	  it.todo("first insurance surcharge: 0-year, plain sword (first quote) → 100 + 10 + 5 = 115 G");
40	  it.todo("follow-up contract discount: second quote in scenario, plain sword (0-year) → 100 + 10 − 15 + 5 = 100 G");
41	
42	  // --- Modifier scope on multi-item policies ---
43	  it.todo("cursed sword + plain amulet → policy 160 G base + 50 curse = 210 + 5 fee = 215 G");
44	
45	  // --- Rounding ---
46	  it.todo("premium calculation yielding 197.5 G → final 198 G (rounded up in MHPCO's favor)");
47	
48	  // --- Integration examples ---
49	  it.todo("newcomer with cursed sword (0 yrs, enchantment 3) → 165 G");
50	  it.todo("long-standing customer's second quote: cursed sword enchantment 7 (3 yrs) → 160 G");
51	
52	  // --- Error handling for quote ---
53	  it.todo("quote with unknown item type (e.g. broomstick) → throws error");
54	
55	  // --- Claim: standard reimbursement ---
56	  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G");
57	  it.todo("rune damaged 200 G → payout 100 G (no special clauses; deductible applies)");
58	
59	  // --- Claim: deductible per damage event ---
60	  it.todo("dragon attack damages sword (500 G) and amulet (300 G) → payout 600 G (deductible applied per item)");
61	
62	  // --- Claim: special clauses ---
63	  it.todo("dragon-material sword enchantment 8, damage 1000 G → payout 400 G (50% then deductible)");
64	  it.todo("dragon-material sword enchantment 9, damage 1000 G → payout 400 G (50% rule wins, then deductible)");
65	  it.todo("dragon-material sword enchantment 5, damage 800 G → payout 700 G (full dragon reimbursement minus deductible)");
66	  it.todo("steel sword enchantment 9, damage 1000 G → payout 400 G (high-enchantment 50% then deductible)");
67	
68	  // --- Claim: cap ---
69	  it.todo("policy with sword and amulet → insurance sum 1600 G, cap 3200 G");
70	  it.todo("cursed sword (insurance value 1000 G, modified premium 165 G) → cap 2000 G (premium modifiers don't raise cap)");
71	  it.todo("policy with sword and 3 runes (block) → insurance sum 1750 G (block discount doesn't affect insurance sum)");
72	
73	  // --- Cap exhaustion across successive claims ---
74	  it.todo("sword (cap 2000 G), two successive claims of 1500 G each → 1st payout 1400, remaining 600; 2nd payout 600, remaining 0");
75	
76	  // --- Multiple items of same type ---
77	  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
78	  it.todo("dragon attack damages both swords (two sword damages) → each treated as separate damage with its own deductible");
79	
80	  // --- Claim error handling ---
81	  it.todo("damages contains more entries of a type than insured → claim rejected (error)");
82	  it.todo("claim references item not in policy → error");
83	  it.todo("claim damage entry with negative amount → error");
84	
85	  // --- Payout rounding ---
86	  it.todo("payout calculation yielding 350.5 G → final 350 G (rounded down in MHPCO's favor)");
87	});
